import{_ as t,o as i,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"79. Best Practice Employment Commitment","description":"","frontmatter":{"title":"79. Best Practice Employment Commitment","eba":"Biomedical Engineers 2025-2028","topics":["ohs","union-matters","flexible-work","preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/union-matters/79-best-practice-employment-commitment.md","filePath":"ebas/biomedical-engineers/union-matters/79-best-practice-employment-commitment.md"}'),r={name:"ebas/biomedical-engineers/union-matters/79-best-practice-employment-commitment.md"};function a(m,e,s,c,p,l){return i(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_79-best-practice-employment-commitment" tabindex="-1">79. Best Practice Employment Commitment <a class="header-anchor" href="#_79-best-practice-employment-commitment" aria-label="Permalink to &quot;79. Best Practice Employment Commitment&quot;">​</a></h1><p><strong>79.1</strong> The parties agree to establish a committee to discuss Best Practice Employment Commitments (BPEC) during the life of the Agreement (BPEC Committee) on matters which include:</p><p><strong>(a)</strong> monitoring the implementation of the Agreement;</p><p><strong>(b)</strong> implementation of a best practice guide to address emerging equity issues arising from flexible working arrangements;</p><p><strong>(c)</strong> any legislative requirement to undertake gender equity activities;</p><p><strong>(d)</strong> an agreed framework distributing, considering and implementing the outcomes of the bullying-related trials conducted within the six health services;</p><p><strong>(e)</strong> an agreed framework for publishing the outcomes of the ‘Thriving in Health’ initiatives that were aimed at preventing psychological harm in the workplace;</p><p><strong>(f)</strong> consolidation of major agreement provisions to reduce complexity and inefficiencies within the public health system;</p><p><strong>(g)</strong> template change impact statements;</p><p><strong>(h)</strong> development of a proposal for a new ‘advanced practice’ classification, to inform the next round of bargaining; and</p><p><strong>(i)</strong> review of Employees’ remuneration with specific regard to work value and interstate comparisons, to inform the next round of bargaining.</p><p><strong>79.2</strong> The BPEC Committee will schedule a minimum of three (3) meetings per year.</p><p><strong>79.3</strong> The BPEC Committee will comprise nominated representatives from the Unions, the VHIA and the Department (as required). The BPEC Committee may, by agreement, establish subgroups or delegate individual matters to a relevant Health Service(s) as required.</p>',13)])])}const h=t(r,[["render",a]]);export{d as __pageData,h as default};
